-- Enrichment marathon batch: Khoros Communities, Kibitzr, Kill Bill, Kimai, Kinde, Kinsta, Kinto, Kissflow

-- ── Khoros Communities ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Enterprise online community platform from Khoros for branded customer support forums, product feedback, and peer-to-peer engagement.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise / Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$1,000-1,500 employees$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Khoros Communities Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Khoros Communities is an enterprise online community platform for customer support and engagement. See features, pricing model, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Khoros Communities is an enterprise-grade online community and customer engagement platform owned by Khoros, LLC, a company formed in March 2019 when private equity firm Vista Equity Partners merged two of its portfolio companies, Lithium Technologies and Spredfast, into a single business named after the Greek word for chorus. Lithium Technologies, the direct ancestor of the Communities product (originally marketed as Lithium Community), had been building branded online support and discussion forums for large consumer brands since the early 2000s and was acquired by Vista in May 2017; Spredfast, a social media management company, was acquired by Vista in October 2018, and the two were combined the following spring to create Khoros. The combined company is headquartered in Austin, Texas, with additional offices historically in San Francisco, Portland, New York City, London, Bangalore, Paris, Sydney, and Hamburg, and has employed roughly 1,000 to 1,500 people in recent years. In 2025, Khoros was acquired by IgniteTech, an operating company known for taking over mature enterprise software businesses, marking another ownership change for the platform. Khoros Communities itself is a hosted, multi-tenant SaaS product designed to let large brands stand up branded discussion forums, support communities, product-feedback and ideation boards, and knowledge bases where customers can help each other, ask questions, and interact directly with a company's support and product teams. The platform is built around discussion threads, structured Q&A, gamification (points, badges, leaderboards, ranks) to encourage repeat participation, granular moderation and content-governance tools, SEO-friendly URL structures intended to help community threads rank in search engines and deflect support tickets, an embeddable widget and API layer for integrating community content into a company's own website or app, and reporting and analytics dashboards that track engagement, deflection rates, and sentiment. Khoros has increasingly layered AI-assisted features into the product, including automated content tagging, suggested replies, and AI search across community knowledge, and it plugs into the broader Khoros suite alongside Khoros Care (social and digital customer service) and Khoros Marketing (social media publishing and listening), letting large enterprises run community, care, and marketing from a single vendor. Khoros does not publish list pricing; the platform is sold through custom, quote-based enterprise contracts scoped to the specific modules purchased, registered-user volume, interaction volume, and contract length, with published estimates suggesting annual contract values commonly fall in the tens of thousands to several hundred thousand dollars, and large enterprise deployments with multiple modules and premium support can exceed one million dollars per year. There is no free tier or self-serve signup; prospective customers work with a Khoros sales team and typically go through a demo and evaluation process before purchase. The target audience is large, well-resourced enterprises and recognizable consumer brands, with companies like Microsoft, Samsung, and Visa cited as customers, that need a dedicated, brand-controlled space for peer-to-peer customer support and community-led product feedback, rather than smaller businesses or startups, for whom the cost and implementation overhead of Khoros would be difficult to justify. Within the online-community software category, Khoros Communities competes most directly with Salesforce Experience Cloud (formerly Community Cloud), Higher Logic (particularly its association and membership-focused communities), inSided (now part of Gainsight, known for its product-community and feedback focus), and Sprinklr's community offering, as well as with lighter-weight and open-source alternatives such as Discourse and Vanilla Forums for organizations that do not need Khoros's enterprise governance layer. Differentiators Khoros emphasizes include its long operating history in the enterprise community space via the Lithium lineage, its combined community-plus-social-customer-care product suite, and its focus on deflection-oriented support communities for very large, high-traffic consumer brands, whereas competitors like Salesforce lean on native CRM integration, Higher Logic leans toward associations and B2B membership organizations, and Discourse and Vanilla serve smaller and mid-market community teams at a fraction of the cost and complexity.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '09a7538e-340b-43e0-b19c-d39402e0b1c4';

