-- ── Kimai ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Kimai is an open source time-tracking application for freelancers and teams, free to self-host or available as a hosted Kimai Cloud subscription.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Kimai Cloud from EUR 2.99/user/month$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Vienna, Austria$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Kimai Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kimai is a free, open-source time-tracking app for freelancers and teams. Compare self-hosted vs Kimai Cloud pricing, features, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kimai is an open-source, web-based time-tracking application whose roots trace back to 2006, when developer Torsten Hoeltge's team began building it as a simple PHP timesheet tool. In 2009, when Torsten no longer had time to continue the project, Vienna-based developer Kevin Papst took over its development, eventually rewriting the codebase into what became known as 'KimaiNext' (now simply the current Kimai) and growing it from a side project into his full-time work, operating today as an independent open-source maintainer and small company based in Vienna, Austria. The software is licensed under the AGPL, so the core self-hosted product is completely free to download, install, and run on a company's own server or via Docker, with no user limits and no feature paywall in the open-source edition itself; Kimai describes itself as a leading open-source time-tracking application, used by freelancers, agencies, and companies to log hours, manage timesheets, and generate client invoices without spreadsheets or manual rounding. Functionally, Kimai organizes tracked time against a hierarchy of customers, projects, and activities, so that hours logged by any number of users roll up cleanly into project- and client-level reporting; at invoicing time, bills are generated directly from actual recorded hours rather than estimates. The platform includes an extensive JSON API for reading and writing timesheet data so it can be embedded into other internal tools, native support for two-factor authentication (TOTP), and single sign-on via external identity providers including LDAP and SAML integrations with providers like Google Workspace and Azure AD, plus a marketplace of official plugins that add advanced invoicing templates, custom reporting, multi-step approval workflows, and expense tracking on top of the free core. For teams that don't want to run their own server, Kimai also operates Kimai Cloud, a fully managed SaaS version hosted on servers in Germany for GDPR compliance, offered on two paid subscription tiers: a Standard plan priced at EUR 2.99 per user per month when billed annually (EUR 3.99 monthly) that includes project time tracking, billable and non-billable hour tracking, invoicing, data export, audit logs, and email support; and a Professional plan at EUR 3.99 per user per month annually (EUR 4.99 monthly) that adds working-hour accounts, public-holiday, vacation, and sick-leave tracking, expense tracking, custom fields, task management, a client-facing customer portal, kiosk mode for shared time-clock devices, daily backups, SAML single sign-on, and a custom domain with SSL. Kimai Cloud also offers a discounted rate of EUR 0.99 per user per month (billed annually) for non-profits and select industries, and every cloud plan includes a 30-day free trial with no setup fees and month-to-month cancellation. The target audience spans the full range from individual freelancers tracking billable hours for a handful of clients up to mid-size agencies and companies needing multi-user timesheets, approval chains, and automated invoicing, with the self-hosted option appealing especially to organizations with data-residency or budget constraints that want to avoid recurring per-seat SaaS costs, and Kimai Cloud appealing to teams that want the same feature set without operating their own server. Within the time-tracking software category, Kimai's most direct competitors are commercial SaaS tools such as Toggl Track, Clockify, Harvest, and TimeCamp, none of which offer a comparably mature, freely self-hostable open-source core; Kimai differentiates itself primarily on that open-source, data-ownership angle combined with genuinely low per-seat SaaS pricing on Kimai Cloud when self-hosting isn't desired, an extensive plugin ecosystem, and deep customization capability through its open API and codebase that closed competitors don't expose.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9723eb0b-ac61-46c1-b15a-4b60b4e6d68f';

