INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5f2b023-ad94-4d73-8138-8c4e2d679679', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Workflow automation$q$, $q$Form-driven approval and process automation for tasks like purchase requests and onboarding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Low-code app builder$q$, $q$Drag-and-drop app building for business users, extensible with custom code for developers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Case management$q$, $q$Structured workflows for handling exceptions and investigations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Kanban-style boards$q$, $q$Lightweight project and task tracking alongside formal workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$AI-powered automation$q$, $q$More than 25 AI-assisted features for generating workflow logic and automating repetitive steps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Datasets and integrations$q$, $q$Connect to and centralize external data sources via Bridges and prebuilt integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Governance and permissioning$q$, $q$Enterprise-grade access control and governance across apps and workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Public and private cloud deployment$q$, $q$Deployment options for customers with stricter data-residency or security needs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Combines no-code business-user tools with developer extensibility on one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Broad feature set spanning workflows, apps, case management, and boards$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Over 25 AI-assisted automation features included without extra surcharges$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Fixed annual pricing agreements avoid per-API or per-AI-call surprise costs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Proven at scale with 10,000-plus customers including major global enterprises$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$No published self-serve pricing, requiring a sales conversation for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Entry-level enterprise packages can be costly for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Implementation and onboarding may require more setup than lightweight tools like Zapier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Dual-headquarters and long company history mean some legacy product complexity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Custom pricing makes it harder to directly compare costs against competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$What is Kissflow used for?$q$, $q$Kissflow is used to build workflow automations, low-code business applications, case management processes, and departmental apps without requiring full custom development.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$How much does Kissflow cost?$q$, $q$Kissflow uses custom, quote-based enterprise pricing; third-party sources report entry packages starting around $1,500 per month for about 50 users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Who founded Kissflow?$q$, $q$Kissflow grew out of OrangeScape Technologies, founded in Chennai, India in 2003 by Suresh Sambandam, who remains the company's CEO.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Does Kissflow require coding?$q$, $q$No, business users can build workflows and apps with a no-code drag-and-drop interface, while developers can extend them with custom code when needed.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Does Kissflow include AI features?$q$, $q$Yes, Kissflow includes more than 25 AI-powered automation features for generating workflows, forms, and summaries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$What are alternatives to Kissflow?$q$, $q$Alternatives include Zapier, Microsoft Power Automate, Appian, Pegasystems (Pega), Nintex, and monday.com.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Approval workflow automation$q$, $q$Organizations automate purchase requests, expense approvals, and employee onboarding processes.$q$, $q$IT and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Citizen-developer app building$q$, $q$Business users build departmental applications without waiting on engineering resources.$q$, $q$Business process owners and citizen developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Enterprise case management$q$, $q$Teams manage exception handling and investigations through structured case workflows.$q$, $q$Large enterprise operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$Enterprise (Custom)$q$, $q$Custom pricing, reportedly from around $1,500/month$q$, $q$Annual agreement$q$, NULL, $q$["Unlimited applications and integrations","Public or private cloud hosting","25+ AI-powered automation features","Enterprise governance and security","Dedicated implementation and support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kissflow is a low-code and no-code workflow automation platform that grew out of OrangeScape Technologies, founded in Chennai, India in 2003 by Suresh Sambandam, who remains founder and CEO. The Kissflow product launched at Google I/O in 2012, after which the company rebranded its U.S. operations as Kissflow, Inc.$q$, $q$The company is dual-headquartered between Chennai, India and the Palo Alto and San Francisco Bay Area in the United States, has scaled to roughly 500-600 employees, and reports serving more than 10,000 customers across over 160 countries, including Airbus, Danone, Michelin, and Pepsi.$q$, $q$Kissflow lets both business users and professional developers build on the same platform, combining a drag-and-drop no-code interface for workflow automation with custom-code extensibility for development teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core building blocks include Workflows for approval-driven process automation, Apps for freeform low-code applications, Boards for Kanban-style task tracking, Cases for exception and investigation management, and Datasets and Bridges for connecting external data.$q$, $q$Kissflow has publicized more than 25 AI-assisted automation features that help generate workflow logic, draft forms, summarize case data, and automate repetitive steps.$q$, $q$Enterprise features include governance and permissioning controls, dashboards and analytics, prebuilt process templates, and support for both public and private cloud deployments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('20fb5336-a872-4aeb-a58f-5087fa3de0ba', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kissflow does not publish fixed self-serve pricing tiers; it sells through custom-quoted, fixed annual enterprise agreements with no surcharges for AI or API usage, scoped to user count, applications, and modules.$q$, $q$Third-party trackers report entry-level enterprise packages starting around $1,500 per month for roughly 50 users and 50 active workflows, with per-user add-ons around $20 to $30 per month and larger deployments commonly running $3,000 to $5,000 or more per month.$q$]::text[], 2);
